# 1. 整数Nを設定する
N = 15

# 2. 1からNまでループ（カウントアップ）処理を行う
for i in range(1, N + 1):

    # ルール1：4と6の両方の倍数（12の倍数）の場合
    if i % 12 == 0:
        print("Twelve!")

    # ルール2：4の倍数の場合
    elif i % 4 == 0:
        print("Four!")

    # ルール3：6の倍数の場合
    elif i % 6 == 0:
        print("Six!")

    # ルール4：それ以外の場合
    else:
        print(i)

# 1からNまでの繰り返しを処理するため、Nを設定します（例として15）
N = 15

# 1からNまで順番に処理を繰り返します（rangeはN+1未満、つまりNまでループします）
for i in range(1, N + 1):

    # 【最優先】3の倍数かつ5の倍数（つまり15の倍数）のときの処理
    if i % 3 == 0 and i % 5 == 0:
        print("FizzBuzz")

    # 3の倍数のときの処理
    elif i % 3 == 0:
        print("Fizz")

    # 5の倍数のときの処理
    elif i % 5 == 0:
        print("Buzz")

    # それ以外の数値はそのまま出力
    else:
        print(i)

